import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Premium / quote basics
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword for a newcomer (first insurance) → 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet for a newcomer → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("single staff for a newcomer → 80 + 8 + 5 = 93 G");
  it.todo("single potion for a newcomer → 40 + 4 + 5 = 49 G");

  // Components
  it.todo("2 runes for a newcomer → base 50, +5 first, +5 fee = 60 G");
  it.todo("3 runes (block) for a newcomer → base 60, +6 first, +5 fee = 71 G");
  it.todo("4 runes for a newcomer → base 100, +10 first, +5 fee = 115 G");
  it.todo("3 runes + 3 moonstones for a newcomer → two blocks (base 120) = 137 G");

  // Modifiers - item-specific
  it.todo("cursed sword for a newcomer → 165 G (integration example)");
  it.todo("high-enchantment sword (level 5) for a newcomer → 100 + 30 surcharge + 13 first + 5 fee = 148 G");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // Modifiers - policy-wide
  it.todo("long-standing customer (2 years) gets 20% loyalty discount");
  it.todo("follow-up contract (second quote in scenario) gets 15% discount");

  // Multi-item policies
  it.todo("cursed sword + plain amulet for newcomer → modifier scope example");

  // Rounding
  it.todo("premium rounding is up (in MHPCO favor)");

  // Long-standing customer's second contract integration example
  it.todo("long-standing customer second contract: cursed sword enchantment 7 → 160 G");

  // Claim basics
  it.todo("regular sword damage 500 → payout 400 (full minus deductible)");
  it.todo("rune damage 200 → payout 100");
  it.todo("high-enchantment sword (8) damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword damage 800 → full reimbursement, then deductible");
  it.todo("dragon-material sword enchantment 9 damage 1000 → 50% wins, then deductible = 400");
  it.todo("deductible per damage event: sword 500 + amulet 300 → payout 600");
  it.todo("cap exhaustion: sword (cap 2000), two 1500 G claims → 1400 then 600");

  // Multi-item / same type
  it.todo("two swords, dragon attack on both → each is separate damage with own deductible");
  it.todo("damage references item not in policy → CLI error");

  // Validation
  it.todo("unknown item type in quote → CLI exits non-zero");
  it.todo("negative damage amount → CLI exits non-zero");
});

