const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_UNIT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const componentBlockBase = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_UNIT_PREMIUM;

const policyBaseFor = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let mainBase = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      mainBase += basePremium(item);
    }
  }
  let componentBase = 0;
  for (const count of componentCounts.values()) {
    componentBase += componentBlockBase(count);
  }
  return mainBase + componentBase;
};

const quotePremium = (items: Item[]): number => {
  const policyBase = policyBaseFor(items);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
};

